template <int NROOTS>
__global__ void KernelERI_ssdp_flat(
    const int32_t* __restrict__ task_spAB,
    const int32_t* __restrict__ task_spCD,
    int ntasks,
    const int32_t* __restrict__ sp_A,
    const int32_t* __restrict__ sp_B,
    const int32_t* __restrict__ sp_pair_start,
    const int32_t* __restrict__ sp_npair,
    const double* __restrict__ shell_cx,
    const double* __restrict__ shell_cy,
    const double* __restrict__ shell_cz,
    const double* __restrict__ pair_eta,
    const double* __restrict__ pair_Px,
    const double* __restrict__ pair_Py,
    const double* __restrict__ pair_Pz,
    const double* __restrict__ pair_cK,
    double* __restrict__ eri_out) {
  const int t = static_cast<int>(blockIdx.x) * static_cast<int>(blockDim.x) + static_cast<int>(threadIdx.x);
  if (t >= ntasks) return;

  const int spAB = static_cast<int>(task_spAB[t]);
  const int spCD = static_cast<int>(task_spCD[t]);
  const int A = static_cast<int>(sp_A[spAB]);
  const int B = static_cast<int>(sp_B[spAB]);
  const int C = static_cast<int>(sp_A[spCD]);
  const int D = static_cast<int>(sp_B[spCD]);

  const double Ax = shell_cx[A];
  const double Ay = shell_cy[A];
  const double Az = shell_cz[A];
  const double Bx = shell_cx[B];
  const double By = shell_cy[B];
  const double Bz = shell_cz[B];
  const double Cx = shell_cx[C];
  const double Cy = shell_cy[C];
  const double Cz = shell_cz[C];
  const double Dx = shell_cx[D];
  const double Dy = shell_cy[D];
  const double Dz = shell_cz[D];

  const double xij = Ax - Bx;
  const double yij = Ay - By;
  const double zij = Az - Bz;
  const double xkl = Cx - Dx;
  const double ykl = Cy - Dy;
  const double zkl = Cz - Dz;
  const double xij2 = xij * xij;
  const double yij2 = yij * yij;
  const double zij2 = zij * zij;
  const double xkl2 = xkl * xkl;
  const double ykl2 = ykl * ykl;
  const double zkl2 = zkl * zkl;

  const int baseAB = static_cast<int>(sp_pair_start[spAB]);
  const int baseCD = static_cast<int>(sp_pair_start[spCD]);
  const int nPairAB = static_cast<int>(sp_npair[spAB]);
  const int nPairCD = static_cast<int>(sp_npair[spCD]);

  constexpr int kFlatStride = 4;
  constexpr int kNComp = 18;
  constexpr int kNMax = 0;
  constexpr int kMMax = 3;

  // G arrays in compact layout: (nmax+1)*(mmax+1) entries per axis.
  double Gx[4];
  double Gy[4];
  double Gz[4];
  double Ux[6];
  double Uy[6];
  double Uz[6];
  double tile[18];
  tile[0] = 0.0;
  tile[1] = 0.0;
  tile[2] = 0.0;
  tile[3] = 0.0;
  tile[4] = 0.0;
  tile[5] = 0.0;
  tile[6] = 0.0;
  tile[7] = 0.0;
  tile[8] = 0.0;
  tile[9] = 0.0;
  tile[10] = 0.0;
  tile[11] = 0.0;
  tile[12] = 0.0;
  tile[13] = 0.0;
  tile[14] = 0.0;
  tile[15] = 0.0;
  tile[16] = 0.0;
  tile[17] = 0.0;

  for (int ip = 0; ip < nPairAB; ++ip) {
    const int ki = baseAB + ip;
    const double p = pair_eta[ki];
    const double Px = pair_Px[ki];
    const double Py = pair_Py[ki];
    const double Pz = pair_Pz[ki];
    const double cKi = pair_cK[ki];
    for (int jp = 0; jp < nPairCD; ++jp) {
      const int kj = baseCD + jp;
      const double q = pair_eta[kj];
      const double Qx = pair_Px[kj];
      const double Qy = pair_Py[kj];
      const double Qz = pair_Pz[kj];
      const double dx = Px - Qx;
      const double dy = Py - Qy;
      const double dz = Pz - Qz;
      const double PQ2 = dx * dx + dy * dy + dz * dz;
      const double denom = p + q;
      const double omega = p * q / denom;
      const double T = omega * PQ2;
      const double base = kTwoPiToFiveHalves / (p * q * ::sqrt(denom)) * cKi * pair_cK[kj];
      double roots[NROOTS], weights[NROOTS];
      cueri_rys::rys_roots_weights<NROOTS>(T, roots, weights);
      for (int u = 0; u < NROOTS; ++u) {
        const double x = roots[u];
        const double w = weights[u];
        const double inv_denom = 1.0 / denom;
        const double B0 = x * 0.5 * inv_denom;
        const double B1 = (1.0 - x) * 0.5 / p + B0;
        const double B1p = (1.0 - x) * 0.5 / q + B0;

        const double Cx_ = (Px - Ax) + (q * inv_denom) * x * (Qx - Px);
        const double Cy_ = (Py - Ay) + (q * inv_denom) * x * (Qy - Py);
        const double Cz_ = (Pz - Az) + (q * inv_denom) * x * (Qz - Pz);
        const double Cpx_ = (Qx - Cx) + (p * inv_denom) * x * (Px - Qx);
        const double Cpy_ = (Qy - Cy) + (p * inv_denom) * x * (Py - Qy);
        const double Cpz_ = (Qz - Cz) + (p * inv_denom) * x * (Pz - Qz);

        compute_G_stride_fixed<kFlatStride, kNMax, kMMax>(Gx, Cx_, Cpx_, B0, B1, B1p);
        compute_G_stride_fixed<kFlatStride, kNMax, kMMax>(Gy, Cy_, Cpy_, B0, B1, B1p);
        compute_G_stride_fixed<kFlatStride, kNMax, kMMax>(Gz, Cz_, Cpz_, B0, B1, B1p);
        const double sc = base * w;
        Ux[0] = Gx[2] * xkl + Gx[3];
        Ux[1] = Gx[2];
        Ux[2] = Gx[1] * xkl + Gx[2];
        Ux[3] = Gx[1];
        Ux[4] = Gx[0] * xkl + Gx[1];
        Ux[5] = Gx[0];
        Uy[0] = Gy[0];
        Uy[1] = Gy[0] * ykl + Gy[1];
        Uy[2] = Gy[1];
        Uy[3] = Gy[1] * ykl + Gy[2];
        Uy[4] = Gy[2];
        Uy[5] = Gy[2] * ykl + Gy[3];
        Uz[0] = Gz[0];
        Uz[1] = Gz[0] * zkl + Gz[1];
        Uz[2] = Gz[1];
        Uz[3] = Gz[1] * zkl + Gz[2];
        Uz[4] = Gz[2];
        Uz[5] = Gz[2] * zkl + Gz[3];
        tile[0] += sc * Ux[0] * Uy[0] * Uz[0];
        tile[1] += sc * Ux[1] * Uy[1] * Uz[0];
        tile[2] += sc * Ux[1] * Uy[0] * Uz[1];
        tile[3] += sc * Ux[2] * Uy[2] * Uz[0];
        tile[4] += sc * Ux[3] * Uy[3] * Uz[0];
        tile[5] += sc * Ux[3] * Uy[2] * Uz[1];
        tile[6] += sc * Ux[2] * Uy[0] * Uz[2];
        tile[7] += sc * Ux[3] * Uy[1] * Uz[2];
        tile[8] += sc * Ux[3] * Uy[0] * Uz[3];
        tile[9] += sc * Ux[4] * Uy[4] * Uz[0];
        tile[10] += sc * Ux[5] * Uy[5] * Uz[0];
        tile[11] += sc * Ux[5] * Uy[4] * Uz[1];
        tile[12] += sc * Ux[4] * Uy[2] * Uz[2];
        tile[13] += sc * Ux[5] * Uy[3] * Uz[2];
        tile[14] += sc * Ux[5] * Uy[2] * Uz[3];
        tile[15] += sc * Ux[4] * Uy[0] * Uz[4];
        tile[16] += sc * Ux[5] * Uy[1] * Uz[4];
        tile[17] += sc * Ux[5] * Uy[0] * Uz[5];
      }
    }
  }

  // Write output tile.
  double* out = eri_out + static_cast<int64_t>(t) * static_cast<int64_t>(18);
  out[0] = tile[0];
  out[1] = tile[1];
  out[2] = tile[2];
  out[3] = tile[3];
  out[4] = tile[4];
  out[5] = tile[5];
  out[6] = tile[6];
  out[7] = tile[7];
  out[8] = tile[8];
  out[9] = tile[9];
  out[10] = tile[10];
  out[11] = tile[11];
  out[12] = tile[12];
  out[13] = tile[13];
  out[14] = tile[14];
  out[15] = tile[15];
  out[16] = tile[16];
  out[17] = tile[17];
}

template <int NROOTS>
__global__ void KernelERI_ssdp_warp_true(
    const int32_t* __restrict__ task_spAB,
    const int32_t* __restrict__ task_spCD,
    int ntasks,
    const int32_t* __restrict__ sp_A,
    const int32_t* __restrict__ sp_B,
    const int32_t* __restrict__ sp_pair_start,
    const int32_t* __restrict__ sp_npair,
    const double* __restrict__ shell_cx,
    const double* __restrict__ shell_cy,
    const double* __restrict__ shell_cz,
    const double* __restrict__ pair_eta,
    const double* __restrict__ pair_Px,
    const double* __restrict__ pair_Py,
    const double* __restrict__ pair_Pz,
    const double* __restrict__ pair_cK,
    double* __restrict__ eri_out) {
  const int lane = static_cast<int>(threadIdx.x) & 31;
  const int warp_id = static_cast<int>(threadIdx.x) >> 5;
  const int warps_per_block = static_cast<int>(blockDim.x) >> 5;
  const int warp_global = static_cast<int>(blockIdx.x) * warps_per_block + warp_id;
  const int subwarp = lane >> 3;
  const int lane8 = lane & 7;
  const int t = warp_global * 4 + subwarp;
  if (t >= ntasks) return;

  const int spAB = static_cast<int>(task_spAB[t]);
  const int spCD = static_cast<int>(task_spCD[t]);
  const int iA = static_cast<int>(sp_A[spAB]);
  const int iB = static_cast<int>(sp_B[spAB]);
  const int iC = static_cast<int>(sp_A[spCD]);
  const int iD = static_cast<int>(sp_B[spCD]);

  const double Ax = shell_cx[iA];
  const double Ay = shell_cy[iA];
  const double Az = shell_cz[iA];
  const double Bx = shell_cx[iB];
  const double By = shell_cy[iB];
  const double Bz = shell_cz[iB];
  const double Cx = shell_cx[iC];
  const double Cy = shell_cy[iC];
  const double Cz = shell_cz[iC];
  const double Dx = shell_cx[iD];
  const double Dy = shell_cy[iD];
  const double Dz = shell_cz[iD];

  const double xij = Ax - Bx;
  const double yij = Ay - By;
  const double zij = Az - Bz;
  const double xkl = Cx - Dx;
  const double ykl = Cy - Dy;
  const double zkl = Cz - Dz;
  const double xij2 = xij * xij;
  const double yij2 = yij * yij;
  const double zij2 = zij * zij;
  const double xkl2 = xkl * xkl;
  const double ykl2 = ykl * ykl;
  const double zkl2 = zkl * zkl;

  const int baseAB = static_cast<int>(sp_pair_start[spAB]);
  const int baseCD = static_cast<int>(sp_pair_start[spCD]);
  const int nPairAB = static_cast<int>(sp_npair[spAB]);
  const int nPairCD = static_cast<int>(sp_npair[spCD]);
  const int totalPairs = nPairAB * nPairCD;

  constexpr int kStride = 5;
  constexpr int kNComp = 18;
  constexpr int kNMax = 0;
  constexpr int kMMax = 3;
  constexpr int kGSize = 25;

  // Per-lane accumulators in registers.
  double acc[kNComp];
  #pragma unroll
  for (int i = 0; i < kNComp; ++i) acc[i] = 0.0;

  // Subwarp-parallel primitive pair loop.
  for (int pair = lane8; pair < totalPairs; pair += 8) {
    const int ip = pair / nPairCD;
    const int jp = pair - ip * nPairCD;
    const int ki = baseAB + ip;
    const int kj = baseCD + jp;

    const double p = pair_eta[ki];
    const double q = pair_eta[kj];
    const double Px = pair_Px[ki];
    const double Py = pair_Py[ki];
    const double Pz = pair_Pz[ki];
    const double Qx = pair_Px[kj];
    const double Qy = pair_Py[kj];
    const double Qz = pair_Pz[kj];

    const double dxPQ = Px - Qx;
    const double dyPQ = Py - Qy;
    const double dzPQ = Pz - Qz;
    const double PQ2 = dxPQ * dxPQ + dyPQ * dyPQ + dzPQ * dzPQ;

    const double denom = p + q;
    const double omega = p * q / denom;
    const double T = omega * PQ2;
    const double base = kTwoPiToFiveHalves / (p * q * ::sqrt(denom)) * pair_cK[ki] * pair_cK[kj];

    // Rys roots/weights in registers — each lane computes independently.
    double roots[NROOTS];
    double weights[NROOTS];
    cueri_rys::rys_roots_weights<NROOTS>(T, roots, weights);

    for (int u = 0; u < NROOTS; ++u) {
      const double x = roots[u];
      const double w = weights[u];
      const double inv_denom = 1.0 / denom;
      const double B0 = x * 0.5 * inv_denom;
      const double B1 = (1.0 - x) * 0.5 / p + B0;
      const double B1p = (1.0 - x) * 0.5 / q + B0;

      const double Cx_ = (Px - Ax) + (q * inv_denom) * x * (Qx - Px);
      const double Cy_ = (Py - Ay) + (q * inv_denom) * x * (Qy - Py);
      const double Cz_ = (Pz - Az) + (q * inv_denom) * x * (Qz - Pz);
      const double Cpx_ = (Qx - Cx) + (p * inv_denom) * x * (Px - Qx);
      const double Cpy_ = (Qy - Cy) + (p * inv_denom) * x * (Py - Qy);
      const double Cpz_ = (Qz - Cz) + (p * inv_denom) * x * (Pz - Qz);

      // G arrays in local memory (registers/L1).
      double Gx[kGSize];
      double Gy[kGSize];
      double Gz[kGSize];
      compute_G_stride_fixed<kStride, kNMax, kMMax>(Gx, Cx_, Cpx_, B0, B1, B1p);
      compute_G_stride_fixed<kStride, kNMax, kMMax>(Gy, Cy_, Cpy_, B0, B1, B1p);
      compute_G_stride_fixed<kStride, kNMax, kMMax>(Gz, Cz_, Cpz_, B0, B1, B1p);

      const double scale = base * w;

      // Accumulate all components.
            acc[0] += scale * (Gx[2] * xkl + Gx[3]) * (Gy[0]) * (Gz[0]);
            acc[1] += scale * (Gx[2]) * (Gy[0] * ykl + Gy[1]) * (Gz[0]);
            acc[2] += scale * (Gx[2]) * (Gy[0]) * (Gz[0] * zkl + Gz[1]);
            acc[3] += scale * (Gx[1] * xkl + Gx[2]) * (Gy[1]) * (Gz[0]);
            acc[4] += scale * (Gx[1]) * (Gy[1] * ykl + Gy[2]) * (Gz[0]);
            acc[5] += scale * (Gx[1]) * (Gy[1]) * (Gz[0] * zkl + Gz[1]);
            acc[6] += scale * (Gx[1] * xkl + Gx[2]) * (Gy[0]) * (Gz[1]);
            acc[7] += scale * (Gx[1]) * (Gy[0] * ykl + Gy[1]) * (Gz[1]);
            acc[8] += scale * (Gx[1]) * (Gy[0]) * (Gz[1] * zkl + Gz[2]);
            acc[9] += scale * (Gx[0] * xkl + Gx[1]) * (Gy[2]) * (Gz[0]);
            acc[10] += scale * (Gx[0]) * (Gy[2] * ykl + Gy[3]) * (Gz[0]);
            acc[11] += scale * (Gx[0]) * (Gy[2]) * (Gz[0] * zkl + Gz[1]);
            acc[12] += scale * (Gx[0] * xkl + Gx[1]) * (Gy[1]) * (Gz[1]);
            acc[13] += scale * (Gx[0]) * (Gy[1] * ykl + Gy[2]) * (Gz[1]);
            acc[14] += scale * (Gx[0]) * (Gy[1]) * (Gz[1] * zkl + Gz[2]);
            acc[15] += scale * (Gx[0] * xkl + Gx[1]) * (Gy[0]) * (Gz[2]);
            acc[16] += scale * (Gx[0]) * (Gy[0] * ykl + Gy[1]) * (Gz[2]);
            acc[17] += scale * (Gx[0]) * (Gy[0]) * (Gz[2] * zkl + Gz[3]);
    }  // for u (Rys roots)
  }  // for pair

  // Subwarp reduction: sum across 8 lanes for this task.
  #pragma unroll
  for (int i = 0; i < kNComp; ++i) {
    acc[i] += __shfl_down_sync(0xFFFFFFFF, acc[i], 4, 8);
    acc[i] += __shfl_down_sync(0xFFFFFFFF, acc[i], 2, 8);
    acc[i] += __shfl_down_sync(0xFFFFFFFF, acc[i], 1, 8);
  }

  if (lane8 == 0) {
    double* out = eri_out + static_cast<int64_t>(t) * static_cast<int64_t>(kNComp);
    #pragma unroll
    for (int i = 0; i < kNComp; ++i) out[i] = acc[i];
  }
}

template <int NROOTS>
__global__ void KernelFusedFock_ssdp_fixed(
    const int32_t* task_spAB,
    const int32_t* task_spCD,
    int ntasks,
    const int32_t* sp_A,
    const int32_t* sp_B,
    const int32_t* sp_pair_start,
    const int32_t* sp_npair,
    const double* shell_cx,
    const double* shell_cy,
    const double* shell_cz,
    const double* pair_eta,
    const double* pair_Px,
    const double* pair_Py,
    const double* pair_Pz,
    const double* pair_cK,
    const int32_t* shell_ao_start,
    int nao,
    const double* D_mat,
    double* F_mat,
    int n_bufs) {
  const int lane = static_cast<int>(threadIdx.x) & 31;
  const int warp_id = static_cast<int>(threadIdx.x) >> 5;
  const int warps_per_block = static_cast<int>(blockDim.x) >> 5;
  const int t = static_cast<int>(blockIdx.x) * warps_per_block + warp_id;
  if (t >= ntasks) return;

  constexpr int kStride = 5;
  constexpr int kNComp = 18;
  constexpr int kNMax = 0;
  constexpr int kMMax = 3;
  constexpr int kGSize = kStride * kStride;
  constexpr int kWarpDoubles = 3 * kGSize + 2 * NROOTS + 11 + kNComp;

  extern __shared__ char sh_raw[];
  double* sh_warp = reinterpret_cast<double*>(sh_raw) + static_cast<int64_t>(warp_id) * kWarpDoubles;
  double* Gx = sh_warp;
  double* Gy = sh_warp + kGSize;
  double* Gz = sh_warp + 2 * kGSize;
  double* sh_roots = sh_warp + 3 * kGSize;
  double* sh_weights = sh_roots + NROOTS;
  double* sh_sc = sh_weights + NROOTS;
  double* tile = sh_sc + 11;

  const int spAB = static_cast<int>(task_spAB[t]);
  const int spCD = static_cast<int>(task_spCD[t]);
  const int A = static_cast<int>(sp_A[spAB]);
  const int B = static_cast<int>(sp_B[spAB]);
  const int C = static_cast<int>(sp_A[spCD]);
  const int D = static_cast<int>(sp_B[spCD]);

  const double Ax = shell_cx[A];
  const double Ay = shell_cy[A];
  const double Az = shell_cz[A];
  const double Bx = shell_cx[B];
  const double By = shell_cy[B];
  const double Bz = shell_cz[B];
  const double Cx = shell_cx[C];
  const double Cy = shell_cy[C];
  const double Cz = shell_cz[C];
  const double Dx = shell_cx[D];
  const double Dy = shell_cy[D];
  const double Dz = shell_cz[D];

  const double xij = Ax - Bx;
  const double yij = Ay - By;
  const double zij = Az - Bz;
  const double xkl = Cx - Dx;
  const double ykl = Cy - Dy;
  const double zkl = Cz - Dz;
  const double xij2 = xij * xij;
  const double yij2 = yij * yij;
  const double zij2 = zij * zij;
  const double xkl2 = xkl * xkl;
  const double ykl2 = ykl * ykl;
  const double zkl2 = zkl * zkl;

  const int baseAB = static_cast<int>(sp_pair_start[spAB]);
  const int baseCD = static_cast<int>(sp_pair_start[spCD]);
  const int nPairAB = static_cast<int>(sp_npair[spAB]);
  const int nPairCD = static_cast<int>(sp_npair[spCD]);

  for (int ebase = 0; ebase < kNComp; ebase += 32) {
    const int e = ebase + lane;
    const bool active = (e < kNComp);
    double val = 0.0;
    for (int ip = 0; ip < nPairAB; ++ip) {
      const int ki = baseAB + ip;
      for (int jp = 0; jp < nPairCD; ++jp) {
        const int kj = baseCD + jp;
        if (lane == 0) {
          sh_sc[1] = pair_eta[ki];
          sh_sc[2] = pair_eta[kj];
          sh_sc[3] = pair_Px[ki];
          sh_sc[4] = pair_Py[ki];
          sh_sc[5] = pair_Pz[ki];
          sh_sc[6] = pair_Px[kj];
          sh_sc[7] = pair_Py[kj];
          sh_sc[8] = pair_Pz[kj];
          const double dx = sh_sc[3] - sh_sc[6];
          const double dy = sh_sc[4] - sh_sc[7];
          const double dz = sh_sc[5] - sh_sc[8];
          const double PQ2 = dx * dx + dy * dy + dz * dz;
          sh_sc[9] = sh_sc[1] + sh_sc[2];
          const double omega = sh_sc[1] * sh_sc[2] / sh_sc[9];
          const double T = omega * PQ2;
          sh_sc[10] = kTwoPiToFiveHalves / (sh_sc[1] * sh_sc[2] * ::sqrt(sh_sc[9])) * pair_cK[ki] * pair_cK[kj];
          cueri_rys::rys_roots_weights<NROOTS>(T, sh_roots, sh_weights);
        }
        __syncwarp();
        for (int u = 0; u < NROOTS; ++u) {
          if (lane == 0) {
            const double x = sh_roots[u];
            const double w = sh_weights[u];
            const double inv_denom = 1.0 / sh_sc[9];
            const double B0 = x * 0.5 * inv_denom;
            const double B1 = (1.0 - x) * 0.5 / sh_sc[1] + B0;
            const double B1p = (1.0 - x) * 0.5 / sh_sc[2] + B0;

            const double Cx_ = (sh_sc[3] - Ax) + (sh_sc[2] * inv_denom) * x * (sh_sc[6] - sh_sc[3]);
            const double Cy_ = (sh_sc[4] - Ay) + (sh_sc[2] * inv_denom) * x * (sh_sc[7] - sh_sc[4]);
            const double Cz_ = (sh_sc[5] - Az) + (sh_sc[2] * inv_denom) * x * (sh_sc[8] - sh_sc[5]);
            const double Cpx_ = (sh_sc[6] - Cx) + (sh_sc[1] * inv_denom) * x * (sh_sc[3] - sh_sc[6]);
            const double Cpy_ = (sh_sc[7] - Cy) + (sh_sc[1] * inv_denom) * x * (sh_sc[4] - sh_sc[7]);
            const double Cpz_ = (sh_sc[8] - Cz) + (sh_sc[1] * inv_denom) * x * (sh_sc[5] - sh_sc[8]);

            compute_G_stride_fixed<kStride, kNMax, kMMax>(Gx, Cx_, Cpx_, B0, B1, B1p);
            compute_G_stride_fixed<kStride, kNMax, kMMax>(Gy, Cy_, Cpy_, B0, B1, B1p);
            compute_G_stride_fixed<kStride, kNMax, kMMax>(Gz, Cz_, Cpz_, B0, B1, B1p);
            sh_sc[0] = sh_sc[10] * w;
          }
          __syncwarp();
          if (active) {
            const double Ix = eval_ssdp_x(e, Gx, xij, xij2, xkl, xkl2);
            const double Iy = eval_ssdp_y(e, Gy, yij, yij2, ykl, ykl2);
            const double Iz = eval_ssdp_z(e, Gz, zij, zij2, zkl, zkl2);
            val += sh_sc[0] * (Ix * Iy * Iz);
          }
          __syncwarp();
        }
      }
    }
    if (active) tile[e] = val;
  }

  __syncwarp();
  {
    constexpr int nA = 1, nB = 1, nC = 6, nD = 3;
    constexpr int nAB = 1;
    constexpr int nCD = 18;
    const int a0 = static_cast<int>(shell_ao_start[A]);
    const int b0 = static_cast<int>(shell_ao_start[B]);
    const int c0 = static_cast<int>(shell_ao_start[C]);
    const int d0 = static_cast<int>(shell_ao_start[D]);
    const bool ab_neq = (A != B);
    const bool cd_neq = (C != D);
    const bool bk_swap = (spAB != spCD);
    const double f_ab = ab_neq ? 2.0 : 1.0;
    const double f_cd = cd_neq ? 2.0 : 1.0;
    const int64_t N = static_cast<int64_t>(nao);
    const int buf_id = static_cast<int>(blockIdx.x) % n_bufs;
    cueri_contract_fock_warp_single(
        tile, D_mat, F_mat, lane,
        nAB, nCD, nA, nB, nC, nD,
        a0, b0, c0, d0,
        ab_neq, cd_neq, bk_swap, f_ab, f_cd, N, n_bufs, buf_id);
  }
}

template <int NROOTS>
__global__ void KernelFusedJK_ssdp_fixed(
    const int32_t* task_spAB,
    const int32_t* task_spCD,
    int ntasks,
    const int32_t* sp_A,
    const int32_t* sp_B,
    const int32_t* sp_pair_start,
    const int32_t* sp_npair,
    const double* shell_cx,
    const double* shell_cy,
    const double* shell_cz,
    const double* pair_eta,
    const double* pair_Px,
    const double* pair_Py,
    const double* pair_Pz,
    const double* pair_cK,
    const int32_t* shell_ao_start,
    int nao,
    const double* D_mat,
    double* J_mat,
    double* K_mat,
    int n_bufs) {
  const int lane = static_cast<int>(threadIdx.x) & 31;
  const int warp_id = static_cast<int>(threadIdx.x) >> 5;
  const int warps_per_block = static_cast<int>(blockDim.x) >> 5;
  const int t = static_cast<int>(blockIdx.x) * warps_per_block + warp_id;
  if (t >= ntasks) return;

  constexpr int kStride = 5;
  constexpr int kNComp = 18;
  constexpr int kNMax = 0;
  constexpr int kMMax = 3;
  constexpr int kGSize = kStride * kStride;
  constexpr int kWarpDoubles = 3 * kGSize + 2 * NROOTS + 11 + kNComp;

  extern __shared__ char sh_raw[];
  double* sh_warp = reinterpret_cast<double*>(sh_raw) + static_cast<int64_t>(warp_id) * kWarpDoubles;
  double* Gx = sh_warp;
  double* Gy = sh_warp + kGSize;
  double* Gz = sh_warp + 2 * kGSize;
  double* sh_roots = sh_warp + 3 * kGSize;
  double* sh_weights = sh_roots + NROOTS;
  double* sh_sc = sh_weights + NROOTS;
  double* tile = sh_sc + 11;

  const int spAB = static_cast<int>(task_spAB[t]);
  const int spCD = static_cast<int>(task_spCD[t]);
  const int A = static_cast<int>(sp_A[spAB]);
  const int B = static_cast<int>(sp_B[spAB]);
  const int C = static_cast<int>(sp_A[spCD]);
  const int D = static_cast<int>(sp_B[spCD]);

  const double Ax = shell_cx[A];
  const double Ay = shell_cy[A];
  const double Az = shell_cz[A];
  const double Bx = shell_cx[B];
  const double By = shell_cy[B];
  const double Bz = shell_cz[B];
  const double Cx = shell_cx[C];
  const double Cy = shell_cy[C];
  const double Cz = shell_cz[C];
  const double Dx = shell_cx[D];
  const double Dy = shell_cy[D];
  const double Dz = shell_cz[D];

  const double xij = Ax - Bx;
  const double yij = Ay - By;
  const double zij = Az - Bz;
  const double xkl = Cx - Dx;
  const double ykl = Cy - Dy;
  const double zkl = Cz - Dz;
  const double xij2 = xij * xij;
  const double yij2 = yij * yij;
  const double zij2 = zij * zij;
  const double xkl2 = xkl * xkl;
  const double ykl2 = ykl * ykl;
  const double zkl2 = zkl * zkl;

  const int baseAB = static_cast<int>(sp_pair_start[spAB]);
  const int baseCD = static_cast<int>(sp_pair_start[spCD]);
  const int nPairAB = static_cast<int>(sp_npair[spAB]);
  const int nPairCD = static_cast<int>(sp_npair[spCD]);

  for (int ebase = 0; ebase < kNComp; ebase += 32) {
    const int e = ebase + lane;
    const bool active = (e < kNComp);
    double val = 0.0;
    for (int ip = 0; ip < nPairAB; ++ip) {
      const int ki = baseAB + ip;
      for (int jp = 0; jp < nPairCD; ++jp) {
        const int kj = baseCD + jp;
        if (lane == 0) {
          sh_sc[1] = pair_eta[ki];
          sh_sc[2] = pair_eta[kj];
          sh_sc[3] = pair_Px[ki];
          sh_sc[4] = pair_Py[ki];
          sh_sc[5] = pair_Pz[ki];
          sh_sc[6] = pair_Px[kj];
          sh_sc[7] = pair_Py[kj];
          sh_sc[8] = pair_Pz[kj];
          const double dx = sh_sc[3] - sh_sc[6];
          const double dy = sh_sc[4] - sh_sc[7];
          const double dz = sh_sc[5] - sh_sc[8];
          const double PQ2 = dx * dx + dy * dy + dz * dz;
          sh_sc[9] = sh_sc[1] + sh_sc[2];
          const double omega = sh_sc[1] * sh_sc[2] / sh_sc[9];
          const double T = omega * PQ2;
          sh_sc[10] = kTwoPiToFiveHalves / (sh_sc[1] * sh_sc[2] * ::sqrt(sh_sc[9])) * pair_cK[ki] * pair_cK[kj];
          cueri_rys::rys_roots_weights<NROOTS>(T, sh_roots, sh_weights);
        }
        __syncwarp();
        for (int u = 0; u < NROOTS; ++u) {
          if (lane == 0) {
            const double x = sh_roots[u];
            const double w = sh_weights[u];
            const double inv_denom = 1.0 / sh_sc[9];
            const double B0 = x * 0.5 * inv_denom;
            const double B1 = (1.0 - x) * 0.5 / sh_sc[1] + B0;
            const double B1p = (1.0 - x) * 0.5 / sh_sc[2] + B0;

            const double Cx_ = (sh_sc[3] - Ax) + (sh_sc[2] * inv_denom) * x * (sh_sc[6] - sh_sc[3]);
            const double Cy_ = (sh_sc[4] - Ay) + (sh_sc[2] * inv_denom) * x * (sh_sc[7] - sh_sc[4]);
            const double Cz_ = (sh_sc[5] - Az) + (sh_sc[2] * inv_denom) * x * (sh_sc[8] - sh_sc[5]);
            const double Cpx_ = (sh_sc[6] - Cx) + (sh_sc[1] * inv_denom) * x * (sh_sc[3] - sh_sc[6]);
            const double Cpy_ = (sh_sc[7] - Cy) + (sh_sc[1] * inv_denom) * x * (sh_sc[4] - sh_sc[7]);
            const double Cpz_ = (sh_sc[8] - Cz) + (sh_sc[1] * inv_denom) * x * (sh_sc[5] - sh_sc[8]);

            compute_G_stride_fixed<kStride, kNMax, kMMax>(Gx, Cx_, Cpx_, B0, B1, B1p);
            compute_G_stride_fixed<kStride, kNMax, kMMax>(Gy, Cy_, Cpy_, B0, B1, B1p);
            compute_G_stride_fixed<kStride, kNMax, kMMax>(Gz, Cz_, Cpz_, B0, B1, B1p);
            sh_sc[0] = sh_sc[10] * w;
          }
          __syncwarp();
          if (active) {
            const double Ix = eval_ssdp_x(e, Gx, xij, xij2, xkl, xkl2);
            const double Iy = eval_ssdp_y(e, Gy, yij, yij2, ykl, ykl2);
            const double Iz = eval_ssdp_z(e, Gz, zij, zij2, zkl, zkl2);
            val += sh_sc[0] * (Ix * Iy * Iz);
          }
          __syncwarp();
        }
      }
    }
    if (active) tile[e] = val;
  }

  __syncwarp();
  {
    constexpr int nA = 1, nB = 1, nC = 6, nD = 3;
    constexpr int nAB = 1;
    constexpr int nCD = 18;
    const int a0 = static_cast<int>(shell_ao_start[A]);
    const int b0 = static_cast<int>(shell_ao_start[B]);
    const int c0 = static_cast<int>(shell_ao_start[C]);
    const int d0 = static_cast<int>(shell_ao_start[D]);
    const bool ab_neq = (A != B);
    const bool cd_neq = (C != D);
    const bool bk_swap = (spAB != spCD);
    const double f_ab = ab_neq ? 2.0 : 1.0;
    const double f_cd = cd_neq ? 2.0 : 1.0;
    const int64_t N = static_cast<int64_t>(nao);
    const int buf_id = static_cast<int>(blockIdx.x) % n_bufs;
    cueri_contract_jk_warp_single(
        tile, D_mat, J_mat, K_mat, lane,
        nAB, nCD, nA, nB, nC, nD,
        a0, b0, c0, d0,
        ab_neq, cd_neq, bk_swap, f_ab, f_cd, N, n_bufs, buf_id);
  }
}

template <int NROOTS>
__global__ void KernelERI_psdp_flat(
    const int32_t* __restrict__ task_spAB,
    const int32_t* __restrict__ task_spCD,
    int ntasks,
    const int32_t* __restrict__ sp_A,
    const int32_t* __restrict__ sp_B,
    const int32_t* __restrict__ sp_pair_start,
    const int32_t* __restrict__ sp_npair,
    const double* __restrict__ shell_cx,
    const double* __restrict__ shell_cy,
    const double* __restrict__ shell_cz,
    const double* __restrict__ pair_eta,
    const double* __restrict__ pair_Px,
    const double* __restrict__ pair_Py,
    const double* __restrict__ pair_Pz,
    const double* __restrict__ pair_cK,
    double* __restrict__ eri_out) {
  const int t = static_cast<int>(blockIdx.x) * static_cast<int>(blockDim.x) + static_cast<int>(threadIdx.x);
  if (t >= ntasks) return;

  const int spAB = static_cast<int>(task_spAB[t]);
  const int spCD = static_cast<int>(task_spCD[t]);
  const int A = static_cast<int>(sp_A[spAB]);
  const int B = static_cast<int>(sp_B[spAB]);
  const int C = static_cast<int>(sp_A[spCD]);
  const int D = static_cast<int>(sp_B[spCD]);

  const double Ax = shell_cx[A];
  const double Ay = shell_cy[A];
  const double Az = shell_cz[A];
  const double Bx = shell_cx[B];
  const double By = shell_cy[B];
  const double Bz = shell_cz[B];
  const double Cx = shell_cx[C];
  const double Cy = shell_cy[C];
  const double Cz = shell_cz[C];
  const double Dx = shell_cx[D];
  const double Dy = shell_cy[D];
  const double Dz = shell_cz[D];

  const double xij = Ax - Bx;
  const double yij = Ay - By;
  const double zij = Az - Bz;
  const double xkl = Cx - Dx;
  const double ykl = Cy - Dy;
  const double zkl = Cz - Dz;
  const double xij2 = xij * xij;
  const double yij2 = yij * yij;
  const double zij2 = zij * zij;
  const double xkl2 = xkl * xkl;
  const double ykl2 = ykl * ykl;
  const double zkl2 = zkl * zkl;

  const int baseAB = static_cast<int>(sp_pair_start[spAB]);
  const int baseCD = static_cast<int>(sp_pair_start[spCD]);
  const int nPairAB = static_cast<int>(sp_npair[spAB]);
  const int nPairCD = static_cast<int>(sp_npair[spCD]);

  constexpr int kFlatStride = 4;
  constexpr int kNComp = 54;
  constexpr int kNMax = 1;
  constexpr int kMMax = 3;

  // G arrays in compact layout: (nmax+1)*(mmax+1) entries per axis.
  double Gx[8];
  double Gy[8];
  double Gz[8];
  double Ux[12];
  double Uy[12];
  double Uz[12];
  double tile[54];
  tile[0] = 0.0;
  tile[1] = 0.0;
  tile[2] = 0.0;
  tile[3] = 0.0;
  tile[4] = 0.0;
  tile[5] = 0.0;
  tile[6] = 0.0;
  tile[7] = 0.0;
  tile[8] = 0.0;
  tile[9] = 0.0;
  tile[10] = 0.0;
  tile[11] = 0.0;
  tile[12] = 0.0;
  tile[13] = 0.0;
  tile[14] = 0.0;
  tile[15] = 0.0;
  tile[16] = 0.0;
  tile[17] = 0.0;
  tile[18] = 0.0;
  tile[19] = 0.0;
  tile[20] = 0.0;
  tile[21] = 0.0;
  tile[22] = 0.0;
  tile[23] = 0.0;
  tile[24] = 0.0;
  tile[25] = 0.0;
  tile[26] = 0.0;
  tile[27] = 0.0;
  tile[28] = 0.0;
  tile[29] = 0.0;
  tile[30] = 0.0;
  tile[31] = 0.0;
  tile[32] = 0.0;
  tile[33] = 0.0;
  tile[34] = 0.0;
  tile[35] = 0.0;
  tile[36] = 0.0;
  tile[37] = 0.0;
  tile[38] = 0.0;
  tile[39] = 0.0;
  tile[40] = 0.0;
  tile[41] = 0.0;
  tile[42] = 0.0;
  tile[43] = 0.0;
  tile[44] = 0.0;
  tile[45] = 0.0;
  tile[46] = 0.0;
  tile[47] = 0.0;
  tile[48] = 0.0;
  tile[49] = 0.0;
  tile[50] = 0.0;
  tile[51] = 0.0;
  tile[52] = 0.0;
  tile[53] = 0.0;

  for (int ip = 0; ip < nPairAB; ++ip) {
    const int ki = baseAB + ip;
    const double p = pair_eta[ki];
    const double Px = pair_Px[ki];
    const double Py = pair_Py[ki];
    const double Pz = pair_Pz[ki];
    const double cKi = pair_cK[ki];
    for (int jp = 0; jp < nPairCD; ++jp) {
      const int kj = baseCD + jp;
      const double q = pair_eta[kj];
      const double Qx = pair_Px[kj];
      const double Qy = pair_Py[kj];
      const double Qz = pair_Pz[kj];
      const double dx = Px - Qx;
      const double dy = Py - Qy;
      const double dz = Pz - Qz;
      const double PQ2 = dx * dx + dy * dy + dz * dz;
      const double denom = p + q;
      const double omega = p * q / denom;
      const double T = omega * PQ2;
      const double base = kTwoPiToFiveHalves / (p * q * ::sqrt(denom)) * cKi * pair_cK[kj];
      double roots[NROOTS], weights[NROOTS];
      cueri_rys::rys_roots_weights<NROOTS>(T, roots, weights);
      for (int u = 0; u < NROOTS; ++u) {
        const double x = roots[u];
        const double w = weights[u];
        const double inv_denom = 1.0 / denom;
        const double B0 = x * 0.5 * inv_denom;
        const double B1 = (1.0 - x) * 0.5 / p + B0;
        const double B1p = (1.0 - x) * 0.5 / q + B0;

        const double Cx_ = (Px - Ax) + (q * inv_denom) * x * (Qx - Px);
        const double Cy_ = (Py - Ay) + (q * inv_denom) * x * (Qy - Py);
        const double Cz_ = (Pz - Az) + (q * inv_denom) * x * (Qz - Pz);
        const double Cpx_ = (Qx - Cx) + (p * inv_denom) * x * (Px - Qx);
        const double Cpy_ = (Qy - Cy) + (p * inv_denom) * x * (Py - Qy);
        const double Cpz_ = (Qz - Cz) + (p * inv_denom) * x * (Pz - Qz);

        compute_G_stride_fixed<kFlatStride, kNMax, kMMax>(Gx, Cx_, Cpx_, B0, B1, B1p);
        compute_G_stride_fixed<kFlatStride, kNMax, kMMax>(Gy, Cy_, Cpy_, B0, B1, B1p);
        compute_G_stride_fixed<kFlatStride, kNMax, kMMax>(Gz, Cz_, Cpz_, B0, B1, B1p);
        const double sc = base * w;
        Ux[0] = Gx[6] * xkl + Gx[7];
        Ux[1] = Gx[6];
        Ux[2] = Gx[5] * xkl + Gx[6];
        Ux[3] = Gx[5];
        Ux[4] = Gx[4] * xkl + Gx[5];
        Ux[5] = Gx[4];
        Ux[6] = Gx[2] * xkl + Gx[3];
        Ux[7] = Gx[2];
        Ux[8] = Gx[1] * xkl + Gx[2];
        Ux[9] = Gx[1];
        Ux[10] = Gx[0] * xkl + Gx[1];
        Ux[11] = Gx[0];
        Uy[0] = Gy[0];
        Uy[1] = Gy[0] * ykl + Gy[1];
        Uy[2] = Gy[1];
        Uy[3] = Gy[1] * ykl + Gy[2];
        Uy[4] = Gy[2];
        Uy[5] = Gy[2] * ykl + Gy[3];
        Uy[6] = Gy[4];
        Uy[7] = Gy[4] * ykl + Gy[5];
        Uy[8] = Gy[5];
        Uy[9] = Gy[5] * ykl + Gy[6];
        Uy[10] = Gy[6];
        Uy[11] = Gy[6] * ykl + Gy[7];
        Uz[0] = Gz[0];
        Uz[1] = Gz[0] * zkl + Gz[1];
        Uz[2] = Gz[1];
        Uz[3] = Gz[1] * zkl + Gz[2];
        Uz[4] = Gz[2];
        Uz[5] = Gz[2] * zkl + Gz[3];
        Uz[6] = Gz[4];
        Uz[7] = Gz[4] * zkl + Gz[5];
        Uz[8] = Gz[5];
        Uz[9] = Gz[5] * zkl + Gz[6];
        Uz[10] = Gz[6];
        Uz[11] = Gz[6] * zkl + Gz[7];
        tile[0] += sc * Ux[0] * Uy[0] * Uz[0];
        tile[1] += sc * Ux[1] * Uy[1] * Uz[0];
        tile[2] += sc * Ux[1] * Uy[0] * Uz[1];
        tile[3] += sc * Ux[2] * Uy[2] * Uz[0];
        tile[4] += sc * Ux[3] * Uy[3] * Uz[0];
        tile[5] += sc * Ux[3] * Uy[2] * Uz[1];
        tile[6] += sc * Ux[2] * Uy[0] * Uz[2];
        tile[7] += sc * Ux[3] * Uy[1] * Uz[2];
        tile[8] += sc * Ux[3] * Uy[0] * Uz[3];
        tile[9] += sc * Ux[4] * Uy[4] * Uz[0];
        tile[10] += sc * Ux[5] * Uy[5] * Uz[0];
        tile[11] += sc * Ux[5] * Uy[4] * Uz[1];
        tile[12] += sc * Ux[4] * Uy[2] * Uz[2];
        tile[13] += sc * Ux[5] * Uy[3] * Uz[2];
        tile[14] += sc * Ux[5] * Uy[2] * Uz[3];
        tile[15] += sc * Ux[4] * Uy[0] * Uz[4];
        tile[16] += sc * Ux[5] * Uy[1] * Uz[4];
        tile[17] += sc * Ux[5] * Uy[0] * Uz[5];
        tile[18] += sc * Ux[6] * Uy[6] * Uz[0];
        tile[19] += sc * Ux[7] * Uy[7] * Uz[0];
        tile[20] += sc * Ux[7] * Uy[6] * Uz[1];
        tile[21] += sc * Ux[8] * Uy[8] * Uz[0];
        tile[22] += sc * Ux[9] * Uy[9] * Uz[0];
        tile[23] += sc * Ux[9] * Uy[8] * Uz[1];
        tile[24] += sc * Ux[8] * Uy[6] * Uz[2];
        tile[25] += sc * Ux[9] * Uy[7] * Uz[2];
        tile[26] += sc * Ux[9] * Uy[6] * Uz[3];
        tile[27] += sc * Ux[10] * Uy[10] * Uz[0];
        tile[28] += sc * Ux[11] * Uy[11] * Uz[0];
        tile[29] += sc * Ux[11] * Uy[10] * Uz[1];
        tile[30] += sc * Ux[10] * Uy[8] * Uz[2];
        tile[31] += sc * Ux[11] * Uy[9] * Uz[2];
        tile[32] += sc * Ux[11] * Uy[8] * Uz[3];
        tile[33] += sc * Ux[10] * Uy[6] * Uz[4];
        tile[34] += sc * Ux[11] * Uy[7] * Uz[4];
        tile[35] += sc * Ux[11] * Uy[6] * Uz[5];
        tile[36] += sc * Ux[6] * Uy[0] * Uz[6];
        tile[37] += sc * Ux[7] * Uy[1] * Uz[6];
        tile[38] += sc * Ux[7] * Uy[0] * Uz[7];
        tile[39] += sc * Ux[8] * Uy[2] * Uz[6];
        tile[40] += sc * Ux[9] * Uy[3] * Uz[6];
        tile[41] += sc * Ux[9] * Uy[2] * Uz[7];
        tile[42] += sc * Ux[8] * Uy[0] * Uz[8];
        tile[43] += sc * Ux[9] * Uy[1] * Uz[8];
        tile[44] += sc * Ux[9] * Uy[0] * Uz[9];
        tile[45] += sc * Ux[10] * Uy[4] * Uz[6];
        tile[46] += sc * Ux[11] * Uy[5] * Uz[6];
        tile[47] += sc * Ux[11] * Uy[4] * Uz[7];
        tile[48] += sc * Ux[10] * Uy[2] * Uz[8];
        tile[49] += sc * Ux[11] * Uy[3] * Uz[8];
        tile[50] += sc * Ux[11] * Uy[2] * Uz[9];
        tile[51] += sc * Ux[10] * Uy[0] * Uz[10];
        tile[52] += sc * Ux[11] * Uy[1] * Uz[10];
        tile[53] += sc * Ux[11] * Uy[0] * Uz[11];
      }
    }
  }

  // Write output tile.
  double* out = eri_out + static_cast<int64_t>(t) * static_cast<int64_t>(54);
  out[0] = tile[0];
  out[1] = tile[1];
  out[2] = tile[2];
  out[3] = tile[3];
  out[4] = tile[4];
  out[5] = tile[5];
  out[6] = tile[6];
  out[7] = tile[7];
  out[8] = tile[8];
  out[9] = tile[9];
  out[10] = tile[10];
  out[11] = tile[11];
  out[12] = tile[12];
  out[13] = tile[13];
  out[14] = tile[14];
  out[15] = tile[15];
  out[16] = tile[16];
  out[17] = tile[17];
  out[18] = tile[18];
  out[19] = tile[19];
  out[20] = tile[20];
  out[21] = tile[21];
  out[22] = tile[22];
  out[23] = tile[23];
  out[24] = tile[24];
  out[25] = tile[25];
  out[26] = tile[26];
  out[27] = tile[27];
  out[28] = tile[28];
  out[29] = tile[29];
  out[30] = tile[30];
  out[31] = tile[31];
  out[32] = tile[32];
  out[33] = tile[33];
  out[34] = tile[34];
  out[35] = tile[35];
  out[36] = tile[36];
  out[37] = tile[37];
  out[38] = tile[38];
  out[39] = tile[39];
  out[40] = tile[40];
  out[41] = tile[41];
  out[42] = tile[42];
  out[43] = tile[43];
  out[44] = tile[44];
  out[45] = tile[45];
  out[46] = tile[46];
  out[47] = tile[47];
  out[48] = tile[48];
  out[49] = tile[49];
  out[50] = tile[50];
  out[51] = tile[51];
  out[52] = tile[52];
  out[53] = tile[53];
}

template <int NROOTS>
__global__ void KernelERI_psdp_warp_true(
    const int32_t* __restrict__ task_spAB,
    const int32_t* __restrict__ task_spCD,
    int ntasks,
    const int32_t* __restrict__ sp_A,
    const int32_t* __restrict__ sp_B,
    const int32_t* __restrict__ sp_pair_start,
    const int32_t* __restrict__ sp_npair,
    const double* __restrict__ shell_cx,
    const double* __restrict__ shell_cy,
    const double* __restrict__ shell_cz,
    const double* __restrict__ pair_eta,
    const double* __restrict__ pair_Px,
    const double* __restrict__ pair_Py,
    const double* __restrict__ pair_Pz,
    const double* __restrict__ pair_cK,
    double* __restrict__ eri_out) {
  const int lane = static_cast<int>(threadIdx.x) & 31;
  const int warp_id = static_cast<int>(threadIdx.x) >> 5;
  const int warps_per_block = static_cast<int>(blockDim.x) >> 5;
  const int t = static_cast<int>(blockIdx.x) * warps_per_block + warp_id;
  if (t >= ntasks) return;

  const int spAB = static_cast<int>(task_spAB[t]);
  const int spCD = static_cast<int>(task_spCD[t]);
  const int iA = static_cast<int>(sp_A[spAB]);
  const int iB = static_cast<int>(sp_B[spAB]);
  const int iC = static_cast<int>(sp_A[spCD]);
  const int iD = static_cast<int>(sp_B[spCD]);

  const double Ax = shell_cx[iA];
  const double Ay = shell_cy[iA];
  const double Az = shell_cz[iA];
  const double Bx = shell_cx[iB];
  const double By = shell_cy[iB];
  const double Bz = shell_cz[iB];
  const double Cx = shell_cx[iC];
  const double Cy = shell_cy[iC];
  const double Cz = shell_cz[iC];
  const double Dx = shell_cx[iD];
  const double Dy = shell_cy[iD];
  const double Dz = shell_cz[iD];

  const double xij = Ax - Bx;
  const double yij = Ay - By;
  const double zij = Az - Bz;
  const double xkl = Cx - Dx;
  const double ykl = Cy - Dy;
  const double zkl = Cz - Dz;
  const double xij2 = xij * xij;
  const double yij2 = yij * yij;
  const double zij2 = zij * zij;
  const double xkl2 = xkl * xkl;
  const double ykl2 = ykl * ykl;
  const double zkl2 = zkl * zkl;

  const int baseAB = static_cast<int>(sp_pair_start[spAB]);
  const int baseCD = static_cast<int>(sp_pair_start[spCD]);
  const int nPairAB = static_cast<int>(sp_npair[spAB]);
  const int nPairCD = static_cast<int>(sp_npair[spCD]);
  const int totalPairs = nPairAB * nPairCD;

  constexpr int kStride = 5;
  constexpr int kNComp = 54;
  constexpr int kNMax = 1;
  constexpr int kMMax = 3;
  constexpr int kGSize = 25;

  // Per-lane accumulators in registers.
  double acc[kNComp];
  #pragma unroll
  for (int i = 0; i < kNComp; ++i) acc[i] = 0.0;

  // Lane-parallel primitive pair loop.
  for (int pair = lane; pair < totalPairs; pair += 32) {
    const int ip = pair / nPairCD;
    const int jp = pair - ip * nPairCD;
    const int ki = baseAB + ip;
    const int kj = baseCD + jp;

    const double p = pair_eta[ki];
    const double q = pair_eta[kj];
    const double Px = pair_Px[ki];
    const double Py = pair_Py[ki];
    const double Pz = pair_Pz[ki];
    const double Qx = pair_Px[kj];
    const double Qy = pair_Py[kj];
    const double Qz = pair_Pz[kj];

    const double dxPQ = Px - Qx;
    const double dyPQ = Py - Qy;
    const double dzPQ = Pz - Qz;
    const double PQ2 = dxPQ * dxPQ + dyPQ * dyPQ + dzPQ * dzPQ;

    const double denom = p + q;
    const double omega = p * q / denom;
    const double T = omega * PQ2;
    const double base = kTwoPiToFiveHalves / (p * q * ::sqrt(denom)) * pair_cK[ki] * pair_cK[kj];

    // Rys roots/weights in registers — each lane computes independently.
    double roots[NROOTS];
    double weights[NROOTS];
    cueri_rys::rys_roots_weights<NROOTS>(T, roots, weights);

    for (int u = 0; u < NROOTS; ++u) {
      const double x = roots[u];
      const double w = weights[u];
      const double inv_denom = 1.0 / denom;
      const double B0 = x * 0.5 * inv_denom;
      const double B1 = (1.0 - x) * 0.5 / p + B0;
      const double B1p = (1.0 - x) * 0.5 / q + B0;

      const double Cx_ = (Px - Ax) + (q * inv_denom) * x * (Qx - Px);
      const double Cy_ = (Py - Ay) + (q * inv_denom) * x * (Qy - Py);
      const double Cz_ = (Pz - Az) + (q * inv_denom) * x * (Qz - Pz);
      const double Cpx_ = (Qx - Cx) + (p * inv_denom) * x * (Px - Qx);
      const double Cpy_ = (Qy - Cy) + (p * inv_denom) * x * (Py - Qy);
      const double Cpz_ = (Qz - Cz) + (p * inv_denom) * x * (Pz - Qz);

      // G arrays in local memory (registers/L1).
      double Gx[kGSize];
      double Gy[kGSize];
      double Gz[kGSize];
      compute_G_stride_fixed<kStride, kNMax, kMMax>(Gx, Cx_, Cpx_, B0, B1, B1p);
      compute_G_stride_fixed<kStride, kNMax, kMMax>(Gy, Cy_, Cpy_, B0, B1, B1p);
      compute_G_stride_fixed<kStride, kNMax, kMMax>(Gz, Cz_, Cpz_, B0, B1, B1p);

      const double scale = base * w;

      // Accumulate all components.
            acc[0] += scale * (Gx[7] * xkl + Gx[8]) * (Gy[0]) * (Gz[0]);
            acc[1] += scale * (Gx[7]) * (Gy[0] * ykl + Gy[1]) * (Gz[0]);
            acc[2] += scale * (Gx[7]) * (Gy[0]) * (Gz[0] * zkl + Gz[1]);
            acc[3] += scale * (Gx[6] * xkl + Gx[7]) * (Gy[1]) * (Gz[0]);
            acc[4] += scale * (Gx[6]) * (Gy[1] * ykl + Gy[2]) * (Gz[0]);
            acc[5] += scale * (Gx[6]) * (Gy[1]) * (Gz[0] * zkl + Gz[1]);
            acc[6] += scale * (Gx[6] * xkl + Gx[7]) * (Gy[0]) * (Gz[1]);
            acc[7] += scale * (Gx[6]) * (Gy[0] * ykl + Gy[1]) * (Gz[1]);
            acc[8] += scale * (Gx[6]) * (Gy[0]) * (Gz[1] * zkl + Gz[2]);
            acc[9] += scale * (Gx[5] * xkl + Gx[6]) * (Gy[2]) * (Gz[0]);
            acc[10] += scale * (Gx[5]) * (Gy[2] * ykl + Gy[3]) * (Gz[0]);
            acc[11] += scale * (Gx[5]) * (Gy[2]) * (Gz[0] * zkl + Gz[1]);
            acc[12] += scale * (Gx[5] * xkl + Gx[6]) * (Gy[1]) * (Gz[1]);
            acc[13] += scale * (Gx[5]) * (Gy[1] * ykl + Gy[2]) * (Gz[1]);
            acc[14] += scale * (Gx[5]) * (Gy[1]) * (Gz[1] * zkl + Gz[2]);
            acc[15] += scale * (Gx[5] * xkl + Gx[6]) * (Gy[0]) * (Gz[2]);
            acc[16] += scale * (Gx[5]) * (Gy[0] * ykl + Gy[1]) * (Gz[2]);
            acc[17] += scale * (Gx[5]) * (Gy[0]) * (Gz[2] * zkl + Gz[3]);
            acc[18] += scale * (Gx[2] * xkl + Gx[3]) * (Gy[5]) * (Gz[0]);
            acc[19] += scale * (Gx[2]) * (Gy[5] * ykl + Gy[6]) * (Gz[0]);
            acc[20] += scale * (Gx[2]) * (Gy[5]) * (Gz[0] * zkl + Gz[1]);
            acc[21] += scale * (Gx[1] * xkl + Gx[2]) * (Gy[6]) * (Gz[0]);
            acc[22] += scale * (Gx[1]) * (Gy[6] * ykl + Gy[7]) * (Gz[0]);
            acc[23] += scale * (Gx[1]) * (Gy[6]) * (Gz[0] * zkl + Gz[1]);
            acc[24] += scale * (Gx[1] * xkl + Gx[2]) * (Gy[5]) * (Gz[1]);
            acc[25] += scale * (Gx[1]) * (Gy[5] * ykl + Gy[6]) * (Gz[1]);
            acc[26] += scale * (Gx[1]) * (Gy[5]) * (Gz[1] * zkl + Gz[2]);
            acc[27] += scale * (Gx[0] * xkl + Gx[1]) * (Gy[7]) * (Gz[0]);
            acc[28] += scale * (Gx[0]) * (Gy[7] * ykl + Gy[8]) * (Gz[0]);
            acc[29] += scale * (Gx[0]) * (Gy[7]) * (Gz[0] * zkl + Gz[1]);
            acc[30] += scale * (Gx[0] * xkl + Gx[1]) * (Gy[6]) * (Gz[1]);
            acc[31] += scale * (Gx[0]) * (Gy[6] * ykl + Gy[7]) * (Gz[1]);
            acc[32] += scale * (Gx[0]) * (Gy[6]) * (Gz[1] * zkl + Gz[2]);
            acc[33] += scale * (Gx[0] * xkl + Gx[1]) * (Gy[5]) * (Gz[2]);
            acc[34] += scale * (Gx[0]) * (Gy[5] * ykl + Gy[6]) * (Gz[2]);
            acc[35] += scale * (Gx[0]) * (Gy[5]) * (Gz[2] * zkl + Gz[3]);
            acc[36] += scale * (Gx[2] * xkl + Gx[3]) * (Gy[0]) * (Gz[5]);
            acc[37] += scale * (Gx[2]) * (Gy[0] * ykl + Gy[1]) * (Gz[5]);
            acc[38] += scale * (Gx[2]) * (Gy[0]) * (Gz[5] * zkl + Gz[6]);
            acc[39] += scale * (Gx[1] * xkl + Gx[2]) * (Gy[1]) * (Gz[5]);
            acc[40] += scale * (Gx[1]) * (Gy[1] * ykl + Gy[2]) * (Gz[5]);
            acc[41] += scale * (Gx[1]) * (Gy[1]) * (Gz[5] * zkl + Gz[6]);
            acc[42] += scale * (Gx[1] * xkl + Gx[2]) * (Gy[0]) * (Gz[6]);
            acc[43] += scale * (Gx[1]) * (Gy[0] * ykl + Gy[1]) * (Gz[6]);
            acc[44] += scale * (Gx[1]) * (Gy[0]) * (Gz[6] * zkl + Gz[7]);
            acc[45] += scale * (Gx[0] * xkl + Gx[1]) * (Gy[2]) * (Gz[5]);
            acc[46] += scale * (Gx[0]) * (Gy[2] * ykl + Gy[3]) * (Gz[5]);
            acc[47] += scale * (Gx[0]) * (Gy[2]) * (Gz[5] * zkl + Gz[6]);
            acc[48] += scale * (Gx[0] * xkl + Gx[1]) * (Gy[1]) * (Gz[6]);
            acc[49] += scale * (Gx[0]) * (Gy[1] * ykl + Gy[2]) * (Gz[6]);
            acc[50] += scale * (Gx[0]) * (Gy[1]) * (Gz[6] * zkl + Gz[7]);
            acc[51] += scale * (Gx[0] * xkl + Gx[1]) * (Gy[0]) * (Gz[7]);
            acc[52] += scale * (Gx[0]) * (Gy[0] * ykl + Gy[1]) * (Gz[7]);
            acc[53] += scale * (Gx[0]) * (Gy[0]) * (Gz[7] * zkl + Gz[8]);
    }  // for u (Rys roots)
  }  // for pair

  // Warp reduction: sum across lanes.
  #pragma unroll
  for (int i = 0; i < kNComp; ++i) {
    #pragma unroll
    for (int offset = 16; offset > 0; offset >>= 1) {
      acc[i] += __shfl_down_sync(0xFFFFFFFF, acc[i], offset);
    }
  }

  // Lane 0 writes output.
  if (lane == 0) {
    double* out = eri_out + static_cast<int64_t>(t) * static_cast<int64_t>(kNComp);
    #pragma unroll
    for (int i = 0; i < kNComp; ++i) out[i] = acc[i];
  }
}

template <int NROOTS>
__global__ void KernelFusedFock_psdp_fixed(
    const int32_t* task_spAB,
    const int32_t* task_spCD,
    int ntasks,
    const int32_t* sp_A,
    const int32_t* sp_B,
    const int32_t* sp_pair_start,
    const int32_t* sp_npair,
    const double* shell_cx,
    const double* shell_cy,
    const double* shell_cz,
    const double* pair_eta,
    const double* pair_Px,
    const double* pair_Py,
    const double* pair_Pz,
    const double* pair_cK,
    const int32_t* shell_ao_start,
    int nao,
    const double* D_mat,
    double* F_mat,
    int n_bufs) {
  const int lane = static_cast<int>(threadIdx.x) & 31;
  const int warp_id = static_cast<int>(threadIdx.x) >> 5;
  const int warps_per_block = static_cast<int>(blockDim.x) >> 5;
  const int t = static_cast<int>(blockIdx.x) * warps_per_block + warp_id;
  if (t >= ntasks) return;

  constexpr int kStride = 5;
  constexpr int kNComp = 54;
  constexpr int kNMax = 1;
  constexpr int kMMax = 3;
  constexpr int kGSize = kStride * kStride;
  constexpr int kWarpDoubles = 3 * kGSize + 2 * NROOTS + 11 + kNComp;

  extern __shared__ char sh_raw[];
  double* sh_warp = reinterpret_cast<double*>(sh_raw) + static_cast<int64_t>(warp_id) * kWarpDoubles;
  double* Gx = sh_warp;
  double* Gy = sh_warp + kGSize;
  double* Gz = sh_warp + 2 * kGSize;
  double* sh_roots = sh_warp + 3 * kGSize;
  double* sh_weights = sh_roots + NROOTS;
  double* sh_sc = sh_weights + NROOTS;
  double* tile = sh_sc + 11;

  const int spAB = static_cast<int>(task_spAB[t]);
  const int spCD = static_cast<int>(task_spCD[t]);
  const int A = static_cast<int>(sp_A[spAB]);
  const int B = static_cast<int>(sp_B[spAB]);
  const int C = static_cast<int>(sp_A[spCD]);
  const int D = static_cast<int>(sp_B[spCD]);

  const double Ax = shell_cx[A];
  const double Ay = shell_cy[A];
  const double Az = shell_cz[A];
  const double Bx = shell_cx[B];
  const double By = shell_cy[B];
  const double Bz = shell_cz[B];
  const double Cx = shell_cx[C];
  const double Cy = shell_cy[C];
  const double Cz = shell_cz[C];
  const double Dx = shell_cx[D];
  const double Dy = shell_cy[D];
  const double Dz = shell_cz[D];

  const double xij = Ax - Bx;
  const double yij = Ay - By;
  const double zij = Az - Bz;
  const double xkl = Cx - Dx;
  const double ykl = Cy - Dy;
  const double zkl = Cz - Dz;
  const double xij2 = xij * xij;
  const double yij2 = yij * yij;
  const double zij2 = zij * zij;
  const double xkl2 = xkl * xkl;
  const double ykl2 = ykl * ykl;
  const double zkl2 = zkl * zkl;

  const int baseAB = static_cast<int>(sp_pair_start[spAB]);
  const int baseCD = static_cast<int>(sp_pair_start[spCD]);
  const int nPairAB = static_cast<int>(sp_npair[spAB]);
  const int nPairCD = static_cast<int>(sp_npair[spCD]);

  for (int ebase = 0; ebase < kNComp; ebase += 32) {
    const int e = ebase + lane;
    const bool active = (e < kNComp);
    double val = 0.0;
    for (int ip = 0; ip < nPairAB; ++ip) {
      const int ki = baseAB + ip;
      for (int jp = 0; jp < nPairCD; ++jp) {
        const int kj = baseCD + jp;
        if (lane == 0) {
          sh_sc[1] = pair_eta[ki];
          sh_sc[2] = pair_eta[kj];
          sh_sc[3] = pair_Px[ki];
          sh_sc[4] = pair_Py[ki];
          sh_sc[5] = pair_Pz[ki];
          sh_sc[6] = pair_Px[kj];
          sh_sc[7] = pair_Py[kj];
          sh_sc[8] = pair_Pz[kj];
          const double dx = sh_sc[3] - sh_sc[6];
          const double dy = sh_sc[4] - sh_sc[7];
          const double dz = sh_sc[5] - sh_sc[8];
          const double PQ2 = dx * dx + dy * dy + dz * dz;
          sh_sc[9] = sh_sc[1] + sh_sc[2];
          const double omega = sh_sc[1] * sh_sc[2] / sh_sc[9];
          const double T = omega * PQ2;
          sh_sc[10] = kTwoPiToFiveHalves / (sh_sc[1] * sh_sc[2] * ::sqrt(sh_sc[9])) * pair_cK[ki] * pair_cK[kj];
          cueri_rys::rys_roots_weights<NROOTS>(T, sh_roots, sh_weights);
        }
        __syncwarp();
        for (int u = 0; u < NROOTS; ++u) {
          if (lane == 0) {
            const double x = sh_roots[u];
            const double w = sh_weights[u];
            const double inv_denom = 1.0 / sh_sc[9];
            const double B0 = x * 0.5 * inv_denom;
            const double B1 = (1.0 - x) * 0.5 / sh_sc[1] + B0;
            const double B1p = (1.0 - x) * 0.5 / sh_sc[2] + B0;

            const double Cx_ = (sh_sc[3] - Ax) + (sh_sc[2] * inv_denom) * x * (sh_sc[6] - sh_sc[3]);
            const double Cy_ = (sh_sc[4] - Ay) + (sh_sc[2] * inv_denom) * x * (sh_sc[7] - sh_sc[4]);
            const double Cz_ = (sh_sc[5] - Az) + (sh_sc[2] * inv_denom) * x * (sh_sc[8] - sh_sc[5]);
            const double Cpx_ = (sh_sc[6] - Cx) + (sh_sc[1] * inv_denom) * x * (sh_sc[3] - sh_sc[6]);
            const double Cpy_ = (sh_sc[7] - Cy) + (sh_sc[1] * inv_denom) * x * (sh_sc[4] - sh_sc[7]);
            const double Cpz_ = (sh_sc[8] - Cz) + (sh_sc[1] * inv_denom) * x * (sh_sc[5] - sh_sc[8]);

            compute_G_stride_fixed<kStride, kNMax, kMMax>(Gx, Cx_, Cpx_, B0, B1, B1p);
            compute_G_stride_fixed<kStride, kNMax, kMMax>(Gy, Cy_, Cpy_, B0, B1, B1p);
            compute_G_stride_fixed<kStride, kNMax, kMMax>(Gz, Cz_, Cpz_, B0, B1, B1p);
            sh_sc[0] = sh_sc[10] * w;
          }
          __syncwarp();
          if (active) {
            const double Ix = eval_psdp_x(e, Gx, xij, xij2, xkl, xkl2);
            const double Iy = eval_psdp_y(e, Gy, yij, yij2, ykl, ykl2);
            const double Iz = eval_psdp_z(e, Gz, zij, zij2, zkl, zkl2);
            val += sh_sc[0] * (Ix * Iy * Iz);
          }
          __syncwarp();
        }
      }
    }
    if (active) tile[e] = val;
  }

  __syncwarp();
  {
    constexpr int nA = 3, nB = 1, nC = 6, nD = 3;
    constexpr int nAB = 3;
    constexpr int nCD = 18;
    const int a0 = static_cast<int>(shell_ao_start[A]);
    const int b0 = static_cast<int>(shell_ao_start[B]);
    const int c0 = static_cast<int>(shell_ao_start[C]);
    const int d0 = static_cast<int>(shell_ao_start[D]);
    const bool ab_neq = (A != B);
    const bool cd_neq = (C != D);
    const bool bk_swap = (spAB != spCD);
    const double f_ab = ab_neq ? 2.0 : 1.0;
    const double f_cd = cd_neq ? 2.0 : 1.0;
    const int64_t N = static_cast<int64_t>(nao);
    const int buf_id = static_cast<int>(blockIdx.x) % n_bufs;
    cueri_contract_fock_warp_single(
        tile, D_mat, F_mat, lane,
        nAB, nCD, nA, nB, nC, nD,
        a0, b0, c0, d0,
        ab_neq, cd_neq, bk_swap, f_ab, f_cd, N, n_bufs, buf_id);
  }
}

template <int NROOTS>
__global__ void KernelFusedJK_psdp_fixed(
    const int32_t* task_spAB,
    const int32_t* task_spCD,
    int ntasks,
    const int32_t* sp_A,
    const int32_t* sp_B,
    const int32_t* sp_pair_start,
    const int32_t* sp_npair,
    const double* shell_cx,
    const double* shell_cy,
    const double* shell_cz,
    const double* pair_eta,
    const double* pair_Px,
    const double* pair_Py,
    const double* pair_Pz,
    const double* pair_cK,
    const int32_t* shell_ao_start,
    int nao,
    const double* D_mat,
    double* J_mat,
    double* K_mat,
    int n_bufs) {
  const int lane = static_cast<int>(threadIdx.x) & 31;
  const int warp_id = static_cast<int>(threadIdx.x) >> 5;
  const int warps_per_block = static_cast<int>(blockDim.x) >> 5;
  const int t = static_cast<int>(blockIdx.x) * warps_per_block + warp_id;
  if (t >= ntasks) return;

  constexpr int kStride = 5;
  constexpr int kNComp = 54;
  constexpr int kNMax = 1;
  constexpr int kMMax = 3;
  constexpr int kGSize = kStride * kStride;
  constexpr int kWarpDoubles = 3 * kGSize + 2 * NROOTS + 11 + kNComp;

  extern __shared__ char sh_raw[];
  double* sh_warp = reinterpret_cast<double*>(sh_raw) + static_cast<int64_t>(warp_id) * kWarpDoubles;
  double* Gx = sh_warp;
  double* Gy = sh_warp + kGSize;
  double* Gz = sh_warp + 2 * kGSize;
  double* sh_roots = sh_warp + 3 * kGSize;
  double* sh_weights = sh_roots + NROOTS;
  double* sh_sc = sh_weights + NROOTS;
  double* tile = sh_sc + 11;

  const int spAB = static_cast<int>(task_spAB[t]);
  const int spCD = static_cast<int>(task_spCD[t]);
  const int A = static_cast<int>(sp_A[spAB]);
  const int B = static_cast<int>(sp_B[spAB]);
  const int C = static_cast<int>(sp_A[spCD]);
  const int D = static_cast<int>(sp_B[spCD]);

  const double Ax = shell_cx[A];
  const double Ay = shell_cy[A];
  const double Az = shell_cz[A];
  const double Bx = shell_cx[B];
  const double By = shell_cy[B];
  const double Bz = shell_cz[B];
  const double Cx = shell_cx[C];
  const double Cy = shell_cy[C];
  const double Cz = shell_cz[C];
  const double Dx = shell_cx[D];
  const double Dy = shell_cy[D];
  const double Dz = shell_cz[D];

  const double xij = Ax - Bx;
  const double yij = Ay - By;
  const double zij = Az - Bz;
  const double xkl = Cx - Dx;
  const double ykl = Cy - Dy;
  const double zkl = Cz - Dz;
  const double xij2 = xij * xij;
  const double yij2 = yij * yij;
  const double zij2 = zij * zij;
  const double xkl2 = xkl * xkl;
  const double ykl2 = ykl * ykl;
  const double zkl2 = zkl * zkl;

  const int baseAB = static_cast<int>(sp_pair_start[spAB]);
  const int baseCD = static_cast<int>(sp_pair_start[spCD]);
  const int nPairAB = static_cast<int>(sp_npair[spAB]);
  const int nPairCD = static_cast<int>(sp_npair[spCD]);

  for (int ebase = 0; ebase < kNComp; ebase += 32) {
    const int e = ebase + lane;
    const bool active = (e < kNComp);
    double val = 0.0;
    for (int ip = 0; ip < nPairAB; ++ip) {
      const int ki = baseAB + ip;
      for (int jp = 0; jp < nPairCD; ++jp) {
        const int kj = baseCD + jp;
        if (lane == 0) {
          sh_sc[1] = pair_eta[ki];
          sh_sc[2] = pair_eta[kj];
          sh_sc[3] = pair_Px[ki];
          sh_sc[4] = pair_Py[ki];
          sh_sc[5] = pair_Pz[ki];
          sh_sc[6] = pair_Px[kj];
          sh_sc[7] = pair_Py[kj];
          sh_sc[8] = pair_Pz[kj];
          const double dx = sh_sc[3] - sh_sc[6];
          const double dy = sh_sc[4] - sh_sc[7];
          const double dz = sh_sc[5] - sh_sc[8];
          const double PQ2 = dx * dx + dy * dy + dz * dz;
          sh_sc[9] = sh_sc[1] + sh_sc[2];
          const double omega = sh_sc[1] * sh_sc[2] / sh_sc[9];
          const double T = omega * PQ2;
          sh_sc[10] = kTwoPiToFiveHalves / (sh_sc[1] * sh_sc[2] * ::sqrt(sh_sc[9])) * pair_cK[ki] * pair_cK[kj];
          cueri_rys::rys_roots_weights<NROOTS>(T, sh_roots, sh_weights);
        }
        __syncwarp();
        for (int u = 0; u < NROOTS; ++u) {
          if (lane == 0) {
            const double x = sh_roots[u];
            const double w = sh_weights[u];
            const double inv_denom = 1.0 / sh_sc[9];
            const double B0 = x * 0.5 * inv_denom;
            const double B1 = (1.0 - x) * 0.5 / sh_sc[1] + B0;
            const double B1p = (1.0 - x) * 0.5 / sh_sc[2] + B0;

            const double Cx_ = (sh_sc[3] - Ax) + (sh_sc[2] * inv_denom) * x * (sh_sc[6] - sh_sc[3]);
            const double Cy_ = (sh_sc[4] - Ay) + (sh_sc[2] * inv_denom) * x * (sh_sc[7] - sh_sc[4]);
            const double Cz_ = (sh_sc[5] - Az) + (sh_sc[2] * inv_denom) * x * (sh_sc[8] - sh_sc[5]);
            const double Cpx_ = (sh_sc[6] - Cx) + (sh_sc[1] * inv_denom) * x * (sh_sc[3] - sh_sc[6]);
            const double Cpy_ = (sh_sc[7] - Cy) + (sh_sc[1] * inv_denom) * x * (sh_sc[4] - sh_sc[7]);
            const double Cpz_ = (sh_sc[8] - Cz) + (sh_sc[1] * inv_denom) * x * (sh_sc[5] - sh_sc[8]);

            compute_G_stride_fixed<kStride, kNMax, kMMax>(Gx, Cx_, Cpx_, B0, B1, B1p);
            compute_G_stride_fixed<kStride, kNMax, kMMax>(Gy, Cy_, Cpy_, B0, B1, B1p);
            compute_G_stride_fixed<kStride, kNMax, kMMax>(Gz, Cz_, Cpz_, B0, B1, B1p);
            sh_sc[0] = sh_sc[10] * w;
          }
          __syncwarp();
          if (active) {
            const double Ix = eval_psdp_x(e, Gx, xij, xij2, xkl, xkl2);
            const double Iy = eval_psdp_y(e, Gy, yij, yij2, ykl, ykl2);
            const double Iz = eval_psdp_z(e, Gz, zij, zij2, zkl, zkl2);
            val += sh_sc[0] * (Ix * Iy * Iz);
          }
          __syncwarp();
        }
      }
    }
    if (active) tile[e] = val;
  }

  __syncwarp();
  {
    constexpr int nA = 3, nB = 1, nC = 6, nD = 3;
    constexpr int nAB = 3;
    constexpr int nCD = 18;
    const int a0 = static_cast<int>(shell_ao_start[A]);
    const int b0 = static_cast<int>(shell_ao_start[B]);
    const int c0 = static_cast<int>(shell_ao_start[C]);
    const int d0 = static_cast<int>(shell_ao_start[D]);
    const bool ab_neq = (A != B);
    const bool cd_neq = (C != D);
    const bool bk_swap = (spAB != spCD);
    const double f_ab = ab_neq ? 2.0 : 1.0;
    const double f_cd = cd_neq ? 2.0 : 1.0;
    const int64_t N = static_cast<int64_t>(nao);
    const int buf_id = static_cast<int>(blockIdx.x) % n_bufs;
    cueri_contract_jk_warp_single(
        tile, D_mat, J_mat, K_mat, lane,
        nAB, nCD, nA, nB, nC, nD,
        a0, b0, c0, d0,
        ab_neq, cd_neq, bk_swap, f_ab, f_cd, N, n_bufs, buf_id);
  }
}

template <int NROOTS>
__global__ void KernelERI_psdd_flat(
    const int32_t* __restrict__ task_spAB,
    const int32_t* __restrict__ task_spCD,
    int ntasks,
    const int32_t* __restrict__ sp_A,
    const int32_t* __restrict__ sp_B,
    const int32_t* __restrict__ sp_pair_start,
    const int32_t* __restrict__ sp_npair,
    const double* __restrict__ shell_cx,
    const double* __restrict__ shell_cy,
    const double* __restrict__ shell_cz,
    const double* __restrict__ pair_eta,
    const double* __restrict__ pair_Px,
    const double* __restrict__ pair_Py,
    const double* __restrict__ pair_Pz,
    const double* __restrict__ pair_cK,
    double* __restrict__ eri_out) {
  const int t = static_cast<int>(blockIdx.x) * static_cast<int>(blockDim.x) + static_cast<int>(threadIdx.x);
  if (t >= ntasks) return;

  const int spAB = static_cast<int>(task_spAB[t]);
  const int spCD = static_cast<int>(task_spCD[t]);
  const int A = static_cast<int>(sp_A[spAB]);
  const int B = static_cast<int>(sp_B[spAB]);
  const int C = static_cast<int>(sp_A[spCD]);
  const int D = static_cast<int>(sp_B[spCD]);

  const double Ax = shell_cx[A];
  const double Ay = shell_cy[A];
  const double Az = shell_cz[A];
  const double Bx = shell_cx[B];
  const double By = shell_cy[B];
  const double Bz = shell_cz[B];
  const double Cx = shell_cx[C];
  const double Cy = shell_cy[C];
  const double Cz = shell_cz[C];
  const double Dx = shell_cx[D];
  const double Dy = shell_cy[D];
  const double Dz = shell_cz[D];

  const double xij = Ax - Bx;
  const double yij = Ay - By;
  const double zij = Az - Bz;
  const double xkl = Cx - Dx;
  const double ykl = Cy - Dy;
  const double zkl = Cz - Dz;
  const double xij2 = xij * xij;
  const double yij2 = yij * yij;
  const double zij2 = zij * zij;
  const double xkl2 = xkl * xkl;
  const double ykl2 = ykl * ykl;
  const double zkl2 = zkl * zkl;

  const int baseAB = static_cast<int>(sp_pair_start[spAB]);
  const int baseCD = static_cast<int>(sp_pair_start[spCD]);
  const int nPairAB = static_cast<int>(sp_npair[spAB]);
  const int nPairCD = static_cast<int>(sp_npair[spCD]);

  constexpr int kFlatStride = 5;
  constexpr int kNComp = 108;
  constexpr int kNMax = 1;
  constexpr int kMMax = 4;

  // G arrays in compact layout: (nmax+1)*(mmax+1) entries per axis.
  double Gx[10];
  double Gy[10];
  double Gz[10];
  double Ux[18];
  double Uy[18];
  double Uz[18];
  double tile[108];
  tile[0] = 0.0;
  tile[1] = 0.0;
  tile[2] = 0.0;
  tile[3] = 0.0;
  tile[4] = 0.0;
  tile[5] = 0.0;
  tile[6] = 0.0;
  tile[7] = 0.0;
  tile[8] = 0.0;
  tile[9] = 0.0;
  tile[10] = 0.0;
  tile[11] = 0.0;
