        tile[90] += sc * Ux[15] * Uy[6] * Uz[9];
        tile[91] += sc * Ux[16] * Uy[7] * Uz[9];
        tile[92] += sc * Ux[16] * Uy[6] * Uz[10];
        tile[93] += sc * Ux[17] * Uy[8] * Uz[9];
        tile[94] += sc * Ux[17] * Uy[7] * Uz[10];
        tile[95] += sc * Ux[17] * Uy[6] * Uz[11];
        tile[96] += sc * Ux[15] * Uy[3] * Uz[12];
