        tile[105] += sc * Ux[17] * Uy[2] * Uz[15];
        tile[106] += sc * Ux[17] * Uy[1] * Uz[16];
        tile[107] += sc * Ux[17] * Uy[0] * Uz[17];
      }
    }
  }

  // Write output tile.
  double* out = eri_out + static_cast<int64_t>(t) * static_cast<int64_t>(108);
  out[0] = tile[0];
