            acc[120] += scale * (Gx[0] * xij * xkl + Gx[5] * xkl + Gx[1] * xij + Gx[6]) * (Gy[1]) * (Gz[6]);
            acc[121] += scale * (Gx[0] * xij + Gx[5]) * (Gy[1] * ykl + Gy[2]) * (Gz[6]);
            acc[122] += scale * (Gx[0] * xij + Gx[5]) * (Gy[1]) * (Gz[6] * zkl + Gz[7]);
            acc[123] += scale * (Gx[0] * xij * xkl + Gx[5] * xkl + Gx[1] * xij + Gx[6]) * (Gy[0]) * (Gz[7]);
