            acc[130] += scale * (Gx[1]) * (Gy[1] * yij * ykl + Gy[6] * ykl + Gy[2] * yij + Gy[7]) * (Gz[5]);
            acc[131] += scale * (Gx[1]) * (Gy[1] * yij + Gy[6]) * (Gz[5] * zkl + Gz[6]);
