            const double Iy = eval_ddss_y(e, Gy, yij, yij2, ykl, ykl2);
            const double Iz = eval_ddss_z(e, Gz, zij, zij2, zkl, zkl2);
            val += sh_sc[0] * (Ix * Iy * Iz);
